void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

  vec3 ret1 = GetPixel(vUv);
  vec3 ret2 = GetPixel((vUv-0.5)*0.5+0.5);
  ret = mix(ret1, ret2, ret2);


  fragColor = ret;
